content:
Bottom tab navigation, iOS-style. Place at the end inside `<Screen>`, after the main content area.

```tsx
import { TabBar, HomeIcon, SearchIcon, SettingsIcon } from "./components/ui";

const [activeTab, setActiveTab] = useState("home");

<TabBar
  tabs={[
    { value: "home", label: "Home", icon: <HomeIcon/> },
    { value: "search", label: "Search", icon: <SearchIcon/> },
    { value: "settings", label: "Settings", icon: <SettingsIcon/> },
  ]}
  value={activeTab}
  onChange={setActiveTab}
/>
```

Limit to 3-5 tabs. When using TabBar with FAB, set `<FAB bottom="tabBar">` so the FAB clears the tabs.

Use `<Input>` and `<TextArea>` from the library for all text inputs.

```tsx
import { Input, TextArea } from "./components/ui";

<Input
  placeholder="Email address"
  type="email"
  value={email}
  onChange={(e) => setEmail(e.target.value)}
  autoFocus
/>

<TextArea
  placeholder="Describe your goal..."
  rows={3}
  value={description}
  onChange={(e) => setDescription(e.target.value)}
/>
```

Never create custom `<input className="border...">` elements — always use the library components.

Use `<SegmentedControl>` for filtering lists or switching views. Supports optional badge counts.

```tsx
import { SegmentedControl } from "./components/ui";

const [filter, setFilter] = useState("all");

<SegmentedControl
  segments={[
    { value: "all", label: "All", badge: items.length },
    { value: "active", label: "Active", badge: activeCount },
    { value: "done", label: "Done", badge: doneCount },
  ]}
  value={filter}
  onChange={setFilter}
/>
```

Place above the list it filters. Works great with Zustand computed selectors.

Always show `<EmptyState>` when a list has no items. Never leave a blank screen.

```tsx
import { EmptyState, InboxIcon } from "./components/ui";

{items.length === 0 ? (
  <EmptyState
    icon={<InboxIcon/>}
    title="No tasks yet"
    description="Tap the + button to create your first task."
  />
) : (
  <div className="space-y-3">
    {items.map(item => <Card key={item.id}>...</Card>)}
  </div>
)}
```

Choose an appropriate icon: `InboxIcon` (empty lists), `SearchIcon` (no search results), `CalendarIcon` (no events), `StarIcon` (no favorites).

Wrap the entire app in `<ThemeProvider>` and provide a dark mode toggle.

```tsx
import { ThemeProvider, useTheme, IconButton, SunIcon, MoonIcon } from "./components/ui";

export default function App() {
  return (
    <ThemeProvider>
      <Screen>
        <AppBar title="My App" trailing={<DarkToggle/>} />
        {/* content */}
      </Screen>
    </ThemeProvider>
  );
}

function DarkToggle() {
  const dark = useTheme((s) => s.dark);
  const toggle = useTheme((s) => s.toggle);
  return (
    <IconButton onClick={toggle} aria-label="Toggle theme">
      {dark ? <SunIcon/> : <MoonIcon/>}
    </IconButton>
  );
}
```

The ThemeProvider adds/removes the `dark` class on `<html>`. All `dark:` Tailwind variants activate automatically.

Smooth transitions for mobile interactions:

```tsx
// Basic color/opacity transition
className="transition-colors duration-200"

// Transform transition (for active press effect)
className="transition-transform active:scale-95"

// Opacity fade
className="transition-opacity duration-300"

// Combined hover/active states
className="transition-all duration-200 hover:bg-gray-50 active:scale-95"

// Conditional opacity
className={`transition-opacity duration-300 ${show ? 'opacity-100' : 'opacity-0'}`}
```

Note: The pre-built components already have `active:scale-*` feedback. Only add transitions to custom elements.

Real-time search filtering pattern for lists.

```tsx
const [search, setSearch] = useState("");

const filtered = items.filter(item =>
  item.name.toLowerCase().includes(search.toLowerCase())
);

// In the main content:
<div className="relative">
  <SearchIcon className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400" />
  <input
    type="text"
    placeholder="Search..."
    value={search}
    onChange={(e) => setSearch(e.target.value)}
    className="w-full pl-10 pr-4 py-2.5 rounded-lg bg-gray-100 dark:bg-gray-800
      text-sm placeholder-gray-400 focus:outline-none focus:ring-2 focus:ring-indigo-500/50"
  />
</div>

{filtered.length === 0 ? (
  <EmptyState icon={<SearchIcon/>} title="No results" description={`No matches for "${search}"`} />
) : (
  <div className="space-y-3">
    {filtered.map(item => ...)}
  </div>
)}
```

Note: Search input can be a plain styled `<input>` since it's not a form field (it's a filter). Always show EmptyState for zero results.

Pattern for building timer or countdown features (meditation, pomodoro, workout).

```tsx
import { useState, useEffect, useRef } from "react";

function useTimer(initialSeconds: number) {
  const [seconds, setSeconds] = useState(initialSeconds);
  const [running, setRunning] = useState(false);
  const intervalRef = useRef<number | null>(null);

  useEffect(() => {
    if (running && seconds > 0) {
      intervalRef.current = window.setInterval(() => {
        setSeconds(s => {
          if (s <= 1) { setRunning(false); return 0; }
          return s - 1;
        });
      }, 1000);
    }
    return () => { if (intervalRef.current) clearInterval(intervalRef.current); };
  }, [running, seconds]);

  const mm = String(Math.floor(seconds / 60)).padStart(2, "0");
  const ss = String(seconds % 60).padStart(2, "0");

  return { seconds, display: `${mm}:${ss}`, running, start: () => setRunning(true),
    pause: () => setRunning(false), reset: () => { setRunning(false); setSeconds(initialSeconds); } };
}

// Display
<div className="flex flex-col items-center justify-center py-16 gap-6">
  <p className="text-6xl font-bold tabular-nums tracking-tight">{timer.display}</p>
  <div className="flex gap-3">
    <Button onClick={timer.running ? timer.pause : timer.start}>
      {timer.running ? "Pause" : "Start"}
    </Button>
    <Button variant="secondary" onClick={timer.reset}>Reset</Button>
  </div>
</div>
```

Reusable pattern for selecting categories or tags.

```tsx
const CATEGORIES = [
  { id: "work", label: "Work", color: "bg-blue-500" },
  { id: "personal", label: "Personal", color: "bg-green-500" },
  { id: "health", label: "Health", color: "bg-red-500" },
  { id: "finance", label: "Finance", color: "bg-amber-500" },
];

// Inside BottomSheet form
<div className="space-y-2">
  <label className="text-sm font-medium text-gray-700 dark:text-gray-300">Category</label>
  <div className="flex flex-wrap gap-2">
    {CATEGORIES.map(cat => (
      <button
        key={cat.id}
        onClick={() => setCategory(cat.id)}
        className={`px-3 py-1.5 rounded-full text-sm font-medium transition-colors
          ${category === cat.id
            ? `${cat.color} text-white`
            : 'bg-gray-100 dark:bg-gray-800 text-gray-600 dark:text-gray-400'}`}
      >
        {cat.label}
      </button>
    ))}
  </div>
</div>
```

Useful for: expense categories, task labels, mood selection, workout types.

Group list items by date with sticky section headers.

```tsx
function groupByDate(items: Item[]): Record<string, Item[]> {
  const groups: Record<string, Item[]> = {};
  for (const item of items) {
    const key = new Date(item.date).toLocaleDateString("en-US", {
      weekday: "long", month: "short", day: "numeric"
    });
    (groups[key] ??= []).push(item);
  }
  return groups;
}

// Render
const grouped = groupByDate(items);

<div className="space-y-6">
  {Object.entries(grouped).map(([date, group]) => (
    <div key={date} className="space-y-2">
      <h3 className="text-xs font-medium uppercase tracking-wider text-gray-500 dark:text-gray-400 px-1">
        {date}
      </h3>
      <div className="space-y-2">
        {group.map(item => <Card key={item.id}>...</Card>)}
      </div>
    </div>
  ))}
</div>
```

Apply to: transaction history, activity logs, journal entries, event timelines.

Standard pattern for creating a Zustand store with localStorage persistence.

```ts
// src/store/appStore.ts
import { create } from "zustand";

interface AppState {
  items: Item[];
  addItem: (item: Omit<Item, "id">) => void;
  removeItem: (id: string) => void;
  toggleItem: (id: string) => void;
}

interface Item {
  id: string;
  name: string;
  done: boolean;
  createdAt: number;
}

const STORAGE_KEY = "myapp_data";

const loadInitial = (): Partial<AppState> => {
  try {
    const raw = localStorage.getItem(STORAGE_KEY);
    return raw ? JSON.parse(raw) : {};
  } catch {
    return {};
  }
};

const saved = loadInitial();

export const useAppStore = create<AppState>((set) => ({
  items: (saved.items as Item[]) ?? [],

  addItem: (data) => set((s) => ({
    items: [...s.items, { ...data, id: crypto.randomUUID(), createdAt: Date.now() }],
  })),

  removeItem: (id) => set((s) => ({
    items: s.items.filter((i) => i.id !== id),
  })),

  toggleItem: (id) => set((s) => ({
    items: s.items.map((i) => i.id === id ? { ...i, done: !i.done } : i),
  })),
}));

// Persist on every change
useAppStore.subscribe((state) => {
  try {
    localStorage.setItem(STORAGE_KEY, JSON.stringify({ items: state.items }));
  } catch {}
});
```

Key: only persist data fields (items), not actions. Use `crypto.randomUUID()` for IDs.

Derive filtered/sorted data from the store using selectors — don't duplicate state.

```ts
// In the store file — add computed getters:
export const useAppStore = create<AppState>((set, get) => ({
  items: [],
  filter: "all" as "all" | "active" | "done",
  setFilter: (f: "all" | "active" | "done") => set({ filter: f }),
  // ... other actions
}));

// In components — use selectors:
const items = useAppStore((s) => s.items);
const filter = useAppStore((s) => s.filter);

// Computed in component (simple and clear)
const filtered = items.filter(item => {
  if (filter === "active") return !item.done;
  if (filter === "done") return item.done;
  return true;
});

const activeCount = items.filter(i => !i.done).length;
const doneCount = items.filter(i => i.done).length;
```

Compute derived values in the component, not in the store. Keep the store flat and simple.

Store pattern for financial tracking apps with categories and totals.

```ts
import { create } from "zustand";

interface Transaction {
  id: string;
  amount: number;      // positive = income, negative = expense
  category: string;
  description: string;
  date: number;        // timestamp
}

interface FinanceState {
  transactions: Transaction[];
  addTransaction: (t: Omit<Transaction, "id" | "date">) => void;
  removeTransaction: (id: string) => void;
}

const STORAGE_KEY = "finance_data";
const saved = (() => {
  try { return JSON.parse(localStorage.getItem(STORAGE_KEY) || "null"); }
  catch { return null; }
})();

export const useFinanceStore = create<FinanceState>((set) => ({
  transactions: saved?.transactions ?? [],

  addTransaction: (t) => set((s) => ({
    transactions: [
      { ...t, id: crypto.randomUUID(), date: Date.now() },
      ...s.transactions,
    ],
  })),

  removeTransaction: (id) => set((s) => ({
    transactions: s.transactions.filter((t) => t.id !== id),
  })),
}));

useFinanceStore.subscribe((s) => {
  try { localStorage.setItem(STORAGE_KEY, JSON.stringify({ transactions: s.transactions })); } catch {}
});

// Computed helpers (use in components)
export function getBalance(txns: Transaction[]) {
  return txns.reduce((sum, t) => sum + t.amount, 0);
}
export function getByCategory(txns: Transaction[]) {
  const map: Record<string, number> = {};
  txns.forEach(t => { map[t.category] = (map[t.category] ?? 0) + Math.abs(t.amount); });
  return Object.entries(map).map(([name, value]) => ({ name, value })).sort((a, b) => b.value - a.value);
}
```

Store pattern for habit tracking with daily completions and streaks.

```ts
import { create } from "zustand";

interface Habit {
  id: string;
  name: string;
  color: string;
  completions: Record<string, boolean>;  // "2026-04-11" → true
}

interface HabitState {
  habits: Habit[];
  addHabit: (name: string, color: string) => void;
  removeHabit: (id: string) => void;
  toggleDay: (habitId: string, date: string) => void;
}

const todayKey = () => new Date().toISOString().slice(0, 10);

const STORAGE_KEY = "habits_data";
const saved = (() => {
  try { return JSON.parse(localStorage.getItem(STORAGE_KEY) || "null"); } catch { return null; }
})();

export const useHabitStore = create<HabitState>((set) => ({
  habits: saved?.habits ?? [],

  addHabit: (name, color) => set((s) => ({
    habits: [...s.habits, { id: crypto.randomUUID(), name, color, completions: {} }],
  })),

  removeHabit: (id) => set((s) => ({
    habits: s.habits.filter((h) => h.id !== id),
  })),

  toggleDay: (habitId, date) => set((s) => ({
    habits: s.habits.map((h) =>
      h.id === habitId
        ? { ...h, completions: { ...h.completions, [date]: !h.completions[date] } }
        : h
    ),
  })),
}));

useHabitStore.subscribe((s) => {
  try { localStorage.setItem(STORAGE_KEY, JSON.stringify({ habits: s.habits })); } catch {}
});

// Streak calculator
export function getStreak(completions: Record<string, boolean>): number {
  let streak = 0;
  const d = new Date();
  while (true) {
    const key = d.toISOString().slice(0, 10);
    if (!completions[key]) break;
    streak++;
    d.setDate(d.getDate() - 1);
  }
  return streak;
}
```

Store pattern for notes or journal entries with search and folders.

```ts
import { create } from "zustand";

interface Note {
  id: string;
  title: string;
  body: string;
  folder: string;
  updatedAt: number;
  createdAt: number;
}

interface NotesState {
  notes: Note[];
  addNote: (title: string, body: string, folder?: string) => void;
  updateNote: (id: string, updates: Partial<Pick<Note, "title" | "body" | "folder">>) => void;
  removeNote: (id: string) => void;
}

const STORAGE_KEY = "notes_data";
const saved = (() => {
  try { return JSON.parse(localStorage.getItem(STORAGE_KEY) || "null"); } catch { return null; }
})();

export const useNotesStore = create<NotesState>((set) => ({
  notes: saved?.notes ?? [],

  addNote: (title, body, folder = "General") => set((s) => ({
    notes: [{
      id: crypto.randomUUID(), title, body, folder,
      createdAt: Date.now(), updatedAt: Date.now(),
    }, ...s.notes],
  })),

  updateNote: (id, updates) => set((s) => ({
    notes: s.notes.map((n) =>
      n.id === id ? { ...n, ...updates, updatedAt: Date.now() } : n
    ),
  })),

  removeNote: (id) => set((s) => ({
    notes: s.notes.filter((n) => n.id !== id),
  })),
}));

useNotesStore.subscribe((s) => {
  try { localStorage.setItem(STORAGE_KEY, JSON.stringify({ notes: s.notes })); } catch {}
});
```

Pattern for managing tab-based navigation with content switching.

```tsx
import { useState } from "react";
import { Screen, AppBar, TabBar, HomeIcon, StarIcon, SettingsIcon } from "./components/ui";

type Tab = "home" | "favorites" | "settings";

export default function App() {
  const [tab, setTab] = useState<Tab>("home");

  return (
    <ThemeProvider>
      <Screen>
        <AppBar title={tab === "home" ? "Home" : tab === "favorites" ? "Favorites" : "Settings"} />

        <main className="flex-1 overflow-y-auto px-5 pb-32 space-y-4">
          {tab === "home" && <HomeScreen />}
          {tab === "favorites" && <FavoritesScreen />}
          {tab === "settings" && <SettingsScreen />}
        </main>

        <TabBar
          tabs={[
            { value: "home", label: "Home", icon: <HomeIcon/> },
            { value: "favorites", label: "Favorites", icon: <StarIcon/> },
            { value: "settings", label: "Settings", icon: <SettingsIcon/> },
          ]}
          value={tab}
          onChange={(v) => setTab(v as Tab)}
        />
      </Screen>
    </ThemeProvider>
  );
}
```

Each screen is a separate component. Tab state is simple `useState` — no router needed for 3-5 screens.

A 7-day completion grid (like GitHub contribution graph) without Recharts.

```tsx
const DAYS = ["Mon", "Tue", "Wed", "Thu", "Fri", "Sat", "Sun"];

function WeekGrid({ completions }: { completions: Record<string, boolean> }) {
  const today = new Date();
  const days = Array.from({ length: 7 }, (_, i) => {
    const d = new Date(today);
    d.setDate(d.getDate() - (6 - i));
    return d.toISOString().slice(0, 10);
  });

  return (
    <div className="flex gap-1.5 justify-between">
      {days.map((date, i) => (
        <div key={date} className="flex flex-col items-center gap-1">
          <span className="text-[10px] text-gray-400">{DAYS[(today.getDay() + i - 6 + 7) % 7]?.slice(0, 1)}</span>
          <div
            className={`w-8 h-8 rounded-lg flex items-center justify-center text-xs font-medium
              ${completions[date]
                ? 'bg-green-500 text-white'
                : 'bg-gray-100 dark:bg-gray-800 text-gray-400'}`}
          >
            {new Date(date).getDate()}
          </div>
        </div>
      ))}
    </div>
  );
}
```

Compact visual showing last 7 days. Green = completed, gray = missed. Works great inside habit cards.

THE MOST COMMON BUG. When rendering multiple Cards as siblings, the parent MUST have `space-y-3` or `space-y-4`.

```tsx
// ❌ BUG — cards will touch with no gap
<div>
  {items.map(item => <Card key={item.id}>...</Card>)}
</div>

// ✅ FIX — always add space-y
<div className="space-y-3">
  {items.map(item => <Card key={item.id}>...</Card>)}
</div>
```

This applies to ANY siblings that should have vertical spacing: Cards, ListItems in separate Cards, section blocks.

NEVER create custom `<button>` or `<input>` elements with Tailwind classes when the library has them.

```tsx
// ❌ BUG — custom button
<button className="bg-blue-500 text-white px-4 py-2 rounded-lg">Save</button>

// ✅ FIX — use library Button
import { Button } from "./components/ui";
<Button>Save</Button>

// ❌ BUG — custom input
<input className="border rounded p-2 w-full" placeholder="Name" />

// ✅ FIX — use library Input
import { Input } from "./components/ui";
<Input placeholder="Name" />
```

The library components have proper dark mode support, active states, and consistent styling. Custom elements break the design.

Always handle the zero-state with `<EmptyState>`. A blank screen confuses users.

```tsx
// ❌ BUG — blank when no items
<div className="space-y-3">
  {items.map(item => <Card key={item.id}>...</Card>)}
</div>

// ✅ FIX — EmptyState fallback
{items.length === 0 ? (
  <EmptyState
    icon={<InboxIcon />}
    title="No items yet"
    description="Tap the + button to add your first item."
  />
) : (
  <div className="space-y-3">
    {items.map(item => <Card key={item.id}>...</Card>)}
  </div>
)}
```

The app MUST be wrapped in `<ThemeProvider>` for dark mode to work.

```tsx
// ❌ BUG — no ThemeProvider
export default function App() {
  return (
    <Screen>
      <AppBar title="My App" />
      ...
    </Screen>
  );
}

// ✅ FIX — wrap in ThemeProvider
export default function App() {
  return (
    <ThemeProvider>
      <Screen>
        <AppBar title="My App" trailing={<DarkToggle />} />
        ...
      </Screen>
    </ThemeProvider>
  );
}
```

Also provide a dark mode toggle somewhere accessible (AppBar trailing is the standard location).

Common v3 patterns that are BROKEN in Tailwind v4:

```tsx
// ❌ BROKEN — removed in v4
className="bg-opacity-50"          // use bg-black/50
className="text-opacity-75"        // use text-white/75
className="border-opacity-25"      // use border-gray-300/25

// ❌ BROKEN — no config file in v4
tailwind.config.js                 // does not exist

// ❌ BROKEN — @apply outside @layer
.my-class { @apply bg-blue-500; }  // don't use @apply at all

// ✅ CORRECT v4 alternatives
className="bg-black/50"            // opacity modifier
className="text-white/75"          // opacity modifier  
className="border-gray-300/25"     // opacity modifier
// No config file needed — CSS-first
// Use inline classes instead of @apply
```

BottomSheet must always start closed. It opens only on user interaction.

```tsx
// ❌ BUG — sheet open by default
const [open, setOpen] = useState(true);

// ✅ FIX — start closed
const [open, setOpen] = useState(false);
```

The FAB or a button triggers `setOpen(true)`. The BottomSheet's `onClose` triggers `setOpen(false)`. After saving, close it: `setOpen(false)`.

The standard Appio app layout structure:

```tsx
import {
  ThemeProvider, Screen, AppBar, FAB, BottomSheet,
  PlusIcon, useTheme, IconButton, SunIcon, MoonIcon
} from "./components/ui";

export default function App() {
  const [sheetOpen, setSheetOpen] = useState(false);

  return (
    <ThemeProvider>
      <Screen>
        {/* 1. AppBar — always at top */}
        <AppBar title="My App" trailing={<DarkToggle />} />

        {/* 2. Main content — scrollable area */}
        <main className="flex-1 overflow-y-auto px-5 pb-32 space-y-4">
          {/* SegmentedControl, stats, lists go here */}
        </main>

        {/* 3. FAB — triggers BottomSheet */}
        <FAB onClick={() => setSheetOpen(true)}><PlusIcon /></FAB>

        {/* 4. BottomSheet — contains forms */}
        <BottomSheet open={sheetOpen} onClose={() => setSheetOpen(false)} title="Add Item">
          {/* form fields */}
        </BottomSheet>
      </Screen>
    </ThemeProvider>
  );
}
```

This is the skeleton for 90% of apps. Variations: add TabBar, swap FAB for inline buttons, add SegmentedControl.

For apps with 3-5 distinct views, use TabBar navigation.

```tsx
export default function App() {
  const [tab, setTab] = useState("home");
  const [sheetOpen, setSheetOpen] = useState(false);

  return (
    <ThemeProvider>
      <Screen>
        <AppBar title={TAB_TITLES[tab]} trailing={<DarkToggle />} />

        <main className="flex-1 overflow-y-auto px-5 pb-32 space-y-4">
          {tab === "home" && <HomeContent />}
          {tab === "stats" && <StatsContent />}
          {tab === "settings" && <SettingsContent />}
        </main>

        <FAB onClick={() => setSheetOpen(true)} bottom="tabBar"><PlusIcon /></FAB>

        <TabBar
          tabs={[
            { value: "home", label: "Home", icon: <HomeIcon /> },
            { value: "stats", label: "Stats", icon: <StarIcon /> },
            { value: "settings", label: "Settings", icon: <SettingsIcon /> },
          ]}
          value={tab}
          onChange={setTab}
        />

        <BottomSheet open={sheetOpen} onClose={() => setSheetOpen(false)} title="Add">
          {/* form */}
        </BottomSheet>
      </Screen>
    </ThemeProvider>
  );
}
```

Key: `FAB bottom="tabBar"` to clear tabs. Each screen is a separate component for clarity.

Complete Create/Read/Update/Delete pattern using Zustand + BottomSheet.

```tsx
// State for form
const [sheetOpen, setSheetOpen] = useState(false);
const [editing, setEditing] = useState<Item | null>(null);
const [name, setName] = useState("");

// Open for create
const openCreate = () => {
  setEditing(null);
  setName("");
  setSheetOpen(true);
};

// Open for edit
const openEdit = (item: Item) => {
  setEditing(item);
  setName(item.name);
  setSheetOpen(true);
};

// Save (create or update)
const handleSave = () => {
  if (editing) {
    updateItem(editing.id, { name });
  } else {
    addItem({ name });
  }
  setSheetOpen(false);
};

// In JSX:
<BottomSheet
  open={sheetOpen}
  onClose={() => setSheetOpen(false)}
  title={editing ? "Edit Item" : "New Item"}
>
  <div className="space-y-3">
