Store pattern for quiz apps with scoring and progress tracking.

```ts
import { create } from "zustand";

interface Question {
  id: string;
  question: string;
  options: string[];
  correctIndex: number;
}

interface QuizState {
  questions: Question[];
  currentIndex: number;
  score: number;
  answers: Record<string, number>;  // questionId → selected index
  answer: (questionId: string, selectedIndex: number) => void;
  next: () => void;
  reset: () => void;
}

export const useQuizStore = create<QuizState>((set, get) => ({
  questions: QUIZ_DATA,  // imported from a data file
  currentIndex: 0,
  score: 0,
  answers: {},

  answer: (questionId, selectedIndex) => {
    const q = get().questions.find(q => q.id === questionId);
    const isCorrect = q ? selectedIndex === q.correctIndex : false;
    set(s => ({
      answers: { ...s.answers, [questionId]: selectedIndex },
      score: isCorrect ? s.score + 1 : s.score,
    }));
  },

  next: () => set(s => ({ currentIndex: s.currentIndex + 1 })),

  reset: () => set({ currentIndex: 0, score: 0, answers: {} }),
}));
```

Persist high scores in localStorage separately. Don't persist quiz progress (restart on app reopen).

Smooth animated number transition for stats and counters.

```tsx
import { useEffect, useState } from "react";

function AnimatedNumber({ value, duration = 500 }: { value: number; duration?: number }) {
  const [display, setDisplay] = useState(value);

  useEffect(() => {
    const start = display;
    const diff = value - start;
    if (diff === 0) return;

    const startTime = Date.now();
    const frame = () => {
      const elapsed = Date.now() - startTime;
      const progress = Math.min(elapsed / duration, 1);
      // Ease-out
      const eased = 1 - Math.pow(1 - progress, 3);
      setDisplay(Math.round(start + diff * eased));
      if (progress < 1) requestAnimationFrame(frame);
    };
    requestAnimationFrame(frame);
  }, [value]);

  return <span className="tabular-nums">{display.toLocaleString()}</span>;
}

// Usage
<p className="text-3xl font-bold">
  <AnimatedNumber value={totalScore} />
</p>
