Store pattern for workout tracking with exercises, sets, and history.

```ts
import { create } from "zustand";

interface WorkoutSet {
  weight: number;
  reps: number;
  done: boolean;
}

interface Exercise {
  id: string;
  name: string;
  sets: WorkoutSet[];
}

interface Workout {
  id: string;
  date: number;
  exercises: Exercise[];
}

interface FitnessState {
  workouts: Workout[];
  currentWorkout: Workout | null;
  startWorkout: () => void;
  addExercise: (name: string) => void;
  addSet: (exerciseId: string) => void;
  updateSet: (exerciseId: string, setIndex: number, data: Partial<WorkoutSet>) => void;
  finishWorkout: () => void;
}

const STORAGE_KEY = "fitness_data";
const saved = (() => {
  try { return JSON.parse(localStorage.getItem(STORAGE_KEY) || "null"); } catch { return null; }
})();

export const useFitnessStore = create<FitnessState>((set, get) => ({
  workouts: saved?.workouts ?? [],
  currentWorkout: null,

  startWorkout: () => set({
    currentWorkout: { id: crypto.randomUUID(), date: Date.now(), exercises: [] },
  }),

  addExercise: (name) => set((s) => ({
    currentWorkout: s.currentWorkout ? {
      ...s.currentWorkout,
      exercises: [...s.currentWorkout.exercises, {
        id: crypto.randomUUID(), name, sets: [{ weight: 0, reps: 0, done: false }],
      }],
    } : null,
  })),

  addSet: (exerciseId) => set((s) => ({
    currentWorkout: s.currentWorkout ? {
      ...s.currentWorkout,
      exercises: s.currentWorkout.exercises.map(e =>
        e.id === exerciseId ? { ...e, sets: [...e.sets, { weight: 0, reps: 0, done: false }] } : e
      ),
    } : null,
  })),

  updateSet: (exerciseId, setIndex, data) => set((s) => ({
    currentWorkout: s.currentWorkout ? {
      ...s.currentWorkout,
      exercises: s.currentWorkout.exercises.map(e =>
        e.id === exerciseId
          ? { ...e, sets: e.sets.map((set, i) => i === setIndex ? { ...set, ...data } : set) }
          : e
      ),
    } : null,
  })),

  finishWorkout: () => set((s) => ({
    workouts: s.currentWorkout ? [s.currentWorkout, ...s.workouts] : s.workouts,
    currentWorkout: null,
  })),
}));

useFitnessStore.subscribe((s) => {
  try { localStorage.setItem(STORAGE_KEY, JSON.stringify({ workouts: s.workouts })); } catch {}
});
```

