<button className="bg-blue-500 text-white rounded-lg px-4 py-2">Save</button>
```

You should NOT need to write any CSS files. All styling is done with Tailwind utility classes inline in JSX.

Use SegmentedControl (not actual swipe) for switching content panels.

```tsx
const TABS = ["Overview", "Details", "History"] as const;
type Tab = (typeof TABS)[number];
const [tab, setTab] = useState<Tab>("Overview");

<SegmentedControl
  segments={TABS.map(t => ({ value: t, label: t }))}
  value={tab}
  onChange={(v) => setTab(v as Tab)}
/>

<div className="mt-4">
  {tab === "Overview" && <OverviewPanel />}
  {tab === "Details" && <DetailsPanel />}
  {tab === "History" && <HistoryPanel />}
</div>
```

Use SegmentedControl for in-page content switching. Use TabBar for app-level navigation (3-5 sections).

Lightweight helper for storing individual values (not full Zustand stores).

```ts
export function loadValue<T>(key: string, fallback: T): T {
  try {
    const raw = localStorage.getItem(key);
    return raw !== null ? JSON.parse(raw) : fallback;
  } catch {
    return fallback;
  }
}

export function saveValue(key: string, value: unknown): void {
  try {
    localStorage.setItem(key, JSON.stringify(value));
  } catch {}
}

// Usage
const [highScore, setHighScore] = useState(() => loadValue("highScore", 0));

const updateScore = (score: number) => {
  if (score > highScore) {
    setHighScore(score);
    saveValue("highScore", score);
  }
};
```

Use for: high scores, onboarding flags, user preferences, last-viewed state.

Pattern for breaking long forms into steps.

```tsx
const STEPS = ["Basic Info", "Details", "Review"];
const [step, setStep] = useState(0);

// Progress indicator
<div className="flex items-center gap-2 px-1 mb-4">
  {STEPS.map((label, i) => (
    <div key={label} className="flex items-center gap-2 flex-1">
      <div className={\}>
        {i < step ? <CheckIcon className="w-3 h-3" /> : i + 1}
      </div>
      {i < STEPS.length - 1 && (
        <div className={\} />
      )}
    </div>
  ))}
</div>

// Step content
{step === 0 && <Step1 />}
{step === 1 && <Step2 />}
{step === 2 && <ReviewStep />}

// Navigation
<div className="flex gap-3 mt-4">
  {step > 0 && <Button variant="secondary" fullWidth onClick={() => setStep(s => s - 1)}>Back</Button>}
  <Button fullWidth onClick={() => step < STEPS.length - 1 ? setStep(s => s + 1) : submit()}>
    {step < STEPS.length - 1 ? "Next" : "Submit"}
  </Button>
</div>
```

Use `useAuth` hook + `<LoginScreen>` for apps that need user accounts. Firebase config is pre-injected at `src/config/firebase.ts`.

```tsx
import { useAuth, LoginScreen, Screen, AppBar } from "./components/ui";
import { firebaseConfig } from "./config/firebase";

export default function App() {
  const { user, loading, signInWithEmail, signUpWithEmail, signInWithGoogle, signOut } = useAuth(firebaseConfig);
  const [authError, setAuthError] = useState("");
  const [authLoading, setAuthLoading] = useState(false);

  if (loading) return <Screen><main className="flex-1 flex items-center justify-center"><p className="text-gray-400">Loading...</p></main></Screen>;

  if (!user) return (
    <LoginScreen
      appName="My App"
      tagline="Your tagline"
      logo={<span className="text-4xl">icon</span>}
      error={authError}
      loading={authLoading}
      onEmailAuth={async (email, password, mode) => {
        setAuthError(""); setAuthLoading(true);
        try {
          if (mode === "login") await signInWithEmail(email, password);
          else await signUpWithEmail(email, password);
        } catch (err: any) { setAuthError(err?.message || "Authentication failed"); }
        finally { setAuthLoading(false); }
      }}
      onGoogleSignIn={signInWithGoogle}
    />
  );

  // Authenticated app content
  return <Screen><AppBar title="Home" trailing={<button onClick={signOut}>Sign Out</button>} />...</Screen>;
}
```

`useAuth(config)` returns: `{ user, loading, signInWithEmail, signUpWithEmail, signInWithGoogle, signInWithApple, signOut }`. The `user` object has: `{ uid, email, displayName, photoURL }`. Auth state persists across sessions. Trigger when prompt mentions: accounts, login, sign in, authentication, users, register.

Use `<NotificationPermission>` to add push notification support. The component handles the full flow: permission request, VAPID subscription, and backend registration. The service worker already has push handlers built in.

```tsx
import { NotificationPermission } from "./components/ui";

// Simple banner prompt:
<NotificationPermission
  message="Get daily reminders for your habits!"
  buttonLabel="Turn on reminders"
/>

// Custom render for more control:
<NotificationPermission>
  {({ permission, requesting, requestPermission }) => (
    permission === "default" ? (
      <Button onClick={requestPermission} disabled={requesting}>
        {requesting ? "Enabling..." : "Enable Notifications"}
      </Button>
    ) : permission === "granted" ? (
      <p className="text-sm text-green-500">Notifications enabled ✓</p>
    ) : null
  )}
</NotificationPermission>
```

Place contextually (e.g. after the user creates their first item), not on app load. The component self-hides if permission is already granted, denied, or dismissed.

Use `<PaywallScreen>` when the user wants pricing, subscriptions, premium features, or in-app purchases. Supports monthly/annual toggle, multiple plan tiers, feature comparison, and restore purchases.

```tsx
import { PaywallScreen } from "./components/ui";

const [showPaywall, setShowPaywall] = useState(false);
const [currentPlan, setCurrentPlan] = useState("free");
const [error, setError] = useState("");
const [loading, setLoading] = useState(false);

{showPaywall && (
  <PaywallScreen
    appName="My App Pro"
    tagline="Unlock all features"
    logo={<span className="text-4xl">⭐</span>}
    currentPlanId={currentPlan}
    error={error}
    loading={loading}
    plans={[
      { id: "free", name: "Free", price: 0, features: ["5 items", "Basic themes", "✗ Cloud sync"] },
      { id: "pro", name: "Pro", price: 4.99, annualPrice: 39.99, featured: true, features: ["Unlimited items", "All themes", "Cloud sync", "Priority support"] },
    ]}
    onSubscribe={async (planId, frequency) => {
      setError(""); setLoading(true);
      try { setCurrentPlan(planId); setShowPaywall(false); }
      catch (err: any) { setError(err?.message || "Payment failed"); }
      finally { setLoading(false); }
    }}
    onRestore={async () => { /* Restore purchases */ }}
  />
)}
```

Props: `appName`, `tagline`, `logo`, `plans` (array with id/name/price/annualPrice?/currency?/description?/features/featured?/badge?), `currentPlanId`, `onSubscribe(planId, frequency)`, `onRestore()`, `loading`, `error`, `hideFrequencyToggle`, `footer`. Prefix features with `"✗ "` to show as excluded. The component handles frequency toggle, savings calculation, and current plan badge internally.

Every multi-tenant Convex table MUST: (1) declare `tenantId: v.string()` (= Firebase uid); (2) define an index whose name starts with `by_tenant`. The pre-build scanner rejects any query that doesn't filter through this index.

```ts
// convex/schema.ts
import { defineSchema, defineTable } from "convex/server";
import { v } from "convex/values";

export default defineSchema({
  tasks: defineTable({
    tenantId: v.string(),          // Firebase uid — required on every row
    title: v.string(),
    completed: v.boolean(),
    createdAt: v.number(),
  })
    .index("by_tenant", ["tenantId"])
    .index("by_tenant_and_completed", ["tenantId", "completed"]),
});
```

Composite indexes (`by_tenant_and_X`) cover common filter combinations. Timestamps are `v.number()` (ms since epoch), not `Date`. IDs are opaque (`v.id("tasks")`) and unguessable.

Use `tenantQuery` / `tenantMutation` from `convex/_helpers.ts` instead of raw `query` / `mutation`. They resolve the Firebase identity once and expose `ctx.tenantId` in the handler.

```ts
// convex/tasks.ts
import { v } from "convex/values";
import { tenantQuery, tenantMutation } from "./_helpers";

export const listTasks = tenantQuery({
  args: {},
  handler: async (ctx) =>
    ctx.db
      .query("tasks")
      .withIndex("by_tenant", (q) => q.eq("tenantId", ctx.tenantId))
      .order("desc")
      .collect(),
});

export const createTask = tenantMutation({
  args: { title: v.string() },
  handler: async (ctx, { title }) =>
    ctx.db.insert("tasks", {
      tenantId: ctx.tenantId,                   // ALWAYS stamp on insert
      title,
      completed: false,
      createdAt: Date.now(),
    }),
});
```

Inside the handler you still call `ctx.db.query(...).withIndex("by_tenant...")` — the helper wraps identity resolution, not query construction. Never call raw `query()` / `mutation()` on tenant tables.

`ctx.db.get(id)` is allowed without a tenant filter (IDs are opaque). But before mutating, always verify `doc.tenantId === ctx.tenantId` to defend against reused IDs and URL-injected IDs.

```ts
export const toggleTask = tenantMutation({
  args: { id: v.id("tasks") },
  handler: async (ctx, { id }) => {
    const task = await ctx.db.get(id);
    if (task === null) throw new Error("not found");
    if (task.tenantId !== ctx.tenantId) throw new Error("not authorised");
    await ctx.db.patch(id, { completed: !task.completed });
  },
});

export const updateTask = tenantMutation({
  args: { id: v.id("tasks"), title: v.string() },
  handler: async (ctx, { id, title }) => {
    const task = await ctx.db.get(id);
    if (task === null) throw new Error("not found");
    if (task.tenantId !== ctx.tenantId) throw new Error("not authorised");
    await ctx.db.patch(id, { title: title.trim() });
  },
});

export const deleteTask = tenantMutation({
  args: { id: v.id("tasks") },
  handler: async (ctx, { id }) => {
    const task = await ctx.db.get(id);
    if (task === null) return;                          // idempotent delete
    if (task.tenantId !== ctx.tenantId) throw new Error("not authorised");
    await ctx.db.delete(id);
  },
});
```

Use `ctx.db.patch(id, partial)` (not replace). Trim and validate inputs before writing.

Relate tables via `v.id("otherTable")`. Each related table still needs its own `tenantId` + `by_tenant` index; cross-references are checked in the handler.

```ts
// convex/schema.ts
export default defineSchema({
  folders: defineTable({
    tenantId: v.string(),
    name: v.string(),
  }).index("by_tenant", ["tenantId"]),

  notes: defineTable({
    tenantId: v.string(),
    title: v.string(),
    folderId: v.optional(v.id("folders")),     // nullable FK
    createdAt: v.number(),
  })
    .index("by_tenant", ["tenantId"])
    .index("by_tenant_and_folder", ["tenantId", "folderId"]),
});
```

When inserting with a foreign key, verify the parent belongs to the same tenant:

```ts
export const createNote = tenantMutation({
  args: { title: v.string(), folderId: v.optional(v.id("folders")) },
  handler: async (ctx, { title, folderId }) => {
    if (folderId !== undefined) {
      const folder = await ctx.db.get(folderId);
      if (folder === null || folder.tenantId !== ctx.tenantId) {
        throw new Error("folder not found");
      }
    }
    return ctx.db.insert("notes", {
      tenantId: ctx.tenantId, title, folderId, createdAt: Date.now(),
    });
  },
});
```

For lists that can grow beyond a few hundred rows, use `.paginate()` on the backend and `usePaginatedQuery` on the frontend. Load more on scroll.

```ts
// convex/messages.ts
import { paginationOptsValidator } from "convex/server";

export const listMessages = tenantQuery({
  args: { paginationOpts: paginationOptsValidator },
  handler: async (ctx, { paginationOpts }) =>
    ctx.db
      .query("messages")
      .withIndex("by_tenant", (q) => q.eq("tenantId", ctx.tenantId))
      .order("desc")
      .paginate(paginationOpts),
});
```

```tsx
// components/MessageList.tsx
import { usePaginatedQuery } from "convex/react";
import { api } from "../convex/_generated/api";

const { results, status, loadMore } = usePaginatedQuery(
  api.messages.listMessages,
  {},
  { initialNumItems: 20 },
);

// status: "CanLoadMore" | "LoadingFirstPage" | "LoadingMore" | "Exhausted"
<Button onClick={() => loadMore(20)} disabled={status !== "CanLoadMore"}>
  Load more
</Button>
```

Never `collect()` unbounded tables — read cost scales with total rows returned, not page size.

Use `crons.ts` for periodic jobs and `ctx.scheduler.runAfter(ms, ref, args)` inside a mutation for one-off delayed work.

```ts
// convex/crons.ts
import { cronJobs } from "convex/server";
import { internal } from "./_generated/api";

const crons = cronJobs();

// Runs every day at 09:00 UTC
crons.daily(
  "send daily reminder",
  { hourUTC: 9, minuteUTC: 0 },
  internal.reminders.sendReminders,
);

// Runs every 15 minutes
crons.interval("cleanup expired", { minutes: 15 }, internal.cleanup.purge);

export default crons;
```

```ts
// Delayed job enqueued from a mutation
export const queueFollowUp = tenantMutation({
  args: { taskId: v.id("tasks") },
  handler: async (ctx, { taskId }) => {
    await ctx.scheduler.runAfter(
      24 * 60 * 60 * 1000,                           // 24h delay in ms
      internal.tasks.sendFollowUp,
      { taskId, tenantId: ctx.tenantId },
    );
  },
});
```

Cron handlers must be `internalMutation` or `internalAction` — they have no user identity. Use `tenantInternalMutation` when the job still reads tenant data (pass `tenantId` as an arg).

`action` is the only Convex handler type that can call `fetch()` or external SDKs. Queries and mutations run inside a deterministic transaction — no network access.

```ts
// convex/openai.ts
import { v } from "convex/values";
import { tenantAction } from "./_helpers";
import { api } from "./_generated/api";

export const summariseNote = tenantAction({
  args: { noteId: v.id("notes") },
  handler: async (ctx, { noteId }) => {
    // 1. Read via a query (actions can't touch ctx.db directly)
    const note = await ctx.runQuery(api.notes.getNote, { id: noteId });
    if (note === null) throw new Error("not found");

    // 2. Call the external service
    const res = await fetch("https://api.openai.com/v1/chat/completions", {
      method: "POST",
      headers: {
        Authorization: `Bearer ${process.env.OPENAI_API_KEY}`,
        "Content-Type": "application/json",
      },
      body: JSON.stringify({
        model: "gpt-4o-mini",
        messages: [{ role: "user", content: `Summarise: ${note.content}` }],
      }),
    });
    const data = await res.json();
    const summary = data.choices[0].message.content;

    // 3. Write results via a mutation
    await ctx.runMutation(api.notes.updateSummary, { id: noteId, summary });
    return summary;
  },
});
```

Actions are NOT reactive — they're one-shot. Read with `ctx.runQuery`, write with `ctx.runMutation`. Never put `fetch` in a mutation; the internal retry loop will cause duplicate side effects.

`useQuery(api.foo.list, args)` subscribes to the server result. The component re-renders automatically when any other user's mutation changes the underlying data — a real-time, live subscription with no polling or manual refetch. Ideal for live leaderboards, chat-like feeds, collaborative dashboards, and anything where multiple users see the same data update simultaneously. Returns `undefined` while loading.

```tsx
import { useQuery } from "convex/react";
import { api } from "../convex/_generated/api";

export function TaskList() {
  const tasks = useQuery(api.tasks.listTasks, {});

  if (tasks === undefined) return <Skeleton />;
  if (tasks.length === 0) return <EmptyState title="No tasks yet" />;

  return (
    <div className="space-y-3">
      {tasks.map((t) => (
        <Card key={t._id}>
          <ListItem title={t.title} subtitle={timeAgo(t.createdAt)} />
        </Card>
      ))}
    </div>
  );
}
```

- Pass the sentinel `"skip"` instead of args to pause the subscription: `useQuery(api.tasks.listTasks, user ? {} : "skip")`.
- Results cache across renders — switching tabs and back is instant.
- Type inference carries through from the server handler's return type; no manual generics.

`.withOptimisticUpdate(patch)` mutates the client-side query cache synchronously, so the UI renders the result before the network roundtrip completes. Critical for perceived performance and offline UX.

```tsx
import { useMutation } from "convex/react";
import { api } from "../convex/_generated/api";

export function TaskItem({ task }: { task: Task }) {
  const toggle = useMutation(api.tasks.toggleTask).withOptimisticUpdate(
    (store, { id }) => {
      const list = store.getQuery(api.tasks.listTasks, {});
      if (list === undefined) return;
      store.setQuery(
        api.tasks.listTasks,
        {},
        list.map((t) =>
          t._id === id ? { ...t, completed: !t.completed } : t,
        ),
      );
    },
  );

  return (
    <ListItem
      title={task.title}
      trailing={<Toggle checked={task.completed} onChange={() => toggle({ id: task._id })} />}
    />
  );
}
```

Apply the envelope to every mutation that changes a currently-visible query result. Skip it for fire-and-forget writes (analytics, background logs). The patch persists across disconnects — airplane-mode taps render instantly and replay on reconnect.

The `useCollection` hook from `@appio/ui/hooks` wraps a Convex list query plus its CRUD mutations in a single call. Type inference carries through from the function refs — no manual generics.

This is the default hook for any app that needs to persist data across devices and keep it in sync — habit trackers, todo lists, notes, shopping lists. The underlying Convex subscription means changes made on one device appear instantly on every other device the user is signed in on.

```tsx
import { useCollection } from "@appio/ui/hooks";
import { api } from "../convex/_generated/api";

export function TaskList() {
  const { data: tasks, loading, add, remove } = useCollection({
    list: api.tasks.listTasks,
    mutations: {
      add: api.tasks.createTask,
      remove: api.tasks.deleteTask,
    },
  });

  if (loading) return <Skeleton />;

  return (
    <>
      <div className="space-y-3">
        {tasks!.map((t) => (
          <ListItem
            key={t._id}
            title={t.title}
            trailing={<IconButton onClick={() => remove!({ id: t._id })}><XIcon/></IconButton>}
          />
        ))}
      </div>
      <FAB onClick={() => add!({ title: "New task" })}><PlusIcon/></FAB>
    </>
  );
}
```

Only configure the mutation slots (`add`, `update`, `remove`) you need — unconfigured slots return `undefined`. For optimistic UI, call `useMutation(ref).withOptimisticUpdate(...)` directly alongside `useCollection`.

Generated apps run against Appio's shared sandbox Convex during preview, then migrate to the user's own Convex account on publish. `useConvexMode` exposes the active mode so UI can reflect it (e.g., a "Preview" banner).

```tsx
import { useConvexMode } from "@appio/ui/hooks";

export function PreviewBanner() {
  const mode = useConvexMode();   // "sandbox" | "published"

  if (mode === "published") return null;

  return (
    <div className="bg-amber-500/10 text-amber-900 dark:text-amber-200 text-xs py-1 text-center">
      Preview — data resets on publish
    </div>
  );
}
```

The mode is set by the template's `ConvexClientProvider` from `CONVEX_MODE` in `config/convex.ts`. On publish, the T3.6 migration flips it to `"published"`. The hook is a plain context read — safe to call anywhere.

The #1 security bug in multi-tenant Convex code (team apps, collaboration tools, anything where each user should only see their own projects / tasks / notes): a query without `.withIndex("by_tenant…")` reads EVERY user's rows. Catastrophic data leak — User A sees User B's private data. The pre-build scanner rejects it, but it's the most common pattern to catch in review.

```ts
// ❌ BUG — returns tasks for EVERY user on the sandbox. Build-time rejection.
export const listTasks = tenantQuery({
  args: {},
  handler: async (ctx) =>
    ctx.db.query("tasks").collect(),
});

// ❌ ALSO BUG — .filter() runs after the index scan; the engine still reads
//              other tenants' rows (latency + cost scale with table size).
export const listTasks = tenantQuery({
  args: {},
  handler: async (ctx) =>
    ctx.db
      .query("tasks")
      .filter((q) => q.eq(q.field("tenantId"), ctx.tenantId))
      .collect(),
});

// ✅ CORRECT — the index restricts the scan to this tenant's rows only.
export const listTasks = tenantQuery({
  args: {},
  handler: async (ctx) =>
    ctx.db
      .query("tasks")
      .withIndex("by_tenant", (q) => q.eq("tenantId", ctx.tenantId))
      .collect(),
});
```

Rule: EVERY `ctx.db.query("X")` must chain `.withIndex("by_tenant…")` with `tenantId` as the first `.eq()`. The scanner accepts both `by_tenant` and composite names like `by_tenant_and_completed`.

`ctx.db.get(id)` returns a row even if it belongs to another tenant — the ID is opaque but NOT permission-checked. Always verify `doc.tenantId === ctx.tenantId` before patching or deleting.

```ts
// ❌ BUG — user can delete any task whose ID they guess or steal from URL.
export const deleteTask = tenantMutation({
  args: { id: v.id("tasks") },
  handler: async (ctx, { id }) => {
    await ctx.db.delete(id);
  },
});

// ❌ ALSO BUG — .get() returns the row, but no ownership check before patch.
export const toggleTask = tenantMutation({
  args: { id: v.id("tasks") },
  handler: async (ctx, { id }) => {
    const task = await ctx.db.get(id);
    if (task === null) throw new Error("not found");
    await ctx.db.patch(id, { completed: !task.completed });
  },
});

// ✅ CORRECT — always check tenantId before mutating.
export const toggleTask = tenantMutation({
  args: { id: v.id("tasks") },
  handler: async (ctx, { id }) => {
    const task = await ctx.db.get(id);
    if (task === null) throw new Error("not found");
    if (task.tenantId !== ctx.tenantId) throw new Error("not authorised");
    await ctx.db.patch(id, { completed: !task.completed });
  },
});
```

The scanner only checks query-time tenant filters; ownership checks inside mutations are the agent's responsibility — one of the few hard rules that lives in prompt guidance rather than static analysis.

The Convex React client already buffers mutations during disconnect and replays them on reconnect, in order. DO NOT add a Zustand/IndexedDB mutation queue that mirrors this — you'll get duplicate writes or race conditions with the framework's own buffer.

```ts
// ❌ BUG — mirrors Convex's internal queue; double-fires on reconnect.
const pendingWrites = useStore((s) => s.pendingWrites);
useEffect(() => {
  if (!navigator.onLine) return;
  pendingWrites.forEach((w) => {
    createTask(w.args);              // Convex ALSO replays this mutation
    clearPendingWrite(w.id);
  });
}, [pendingWrites]);

// ❌ BUG — manual retry wrapper. Convex retries internally.
const retryCreateTask = async (args) => {
  for (let i = 0; i < 3; i++) {
    try { return await createTask(args); }
    catch { await sleep(1000 * (i + 1)); }
  }
};

// ✅ CORRECT — trust Convex. Optimistic update for instant UI, no queue.
const createTask = useMutation(api.tasks.createTask).withOptimisticUpdate(
  (store, args) => { /* patch cache */ }
);
```

What you CAN add: an audit log (observability, not durability) that tags writes with `localId` and records ack timestamps — useful for financial / healthcare apps. Convex still owns the queue.

Essential for iPhone and Android apps where the user might disconnect — airplane mode, subway, backgrounding the app for a few minutes — and return expecting fresh data. iOS aggressively suspends WebViews in the background; the Convex WebSocket drops during suspend. Touch the client on `appStateChange` to trigger an automatic reconnect — cheap and idempotent.

```tsx
import { App } from "@capacitor/app";
import { useConvex } from "convex/react";
import { useEffect } from "react";

export function useConvexResume() {
  const convex = useConvex();

  useEffect(() => {
    const sub = App.addListener("appStateChange", ({ isActive }) => {
      if (!isActive) return;
      // Touching connectionState() triggers an internal reconnect check.
      void convex.connectionState();
    });
    return () => { void sub.remove(); };
  }, [convex]);
}
```

```tsx
// Usage at the app root, inside ConvexProvider
function App() {
  useConvexResume();
  return <RestOfApp />;
}
```

Without this, returning from background shows stale UI for 1–5 s until the next user interaction nudges the client. With it, reconnect starts immediately and fresh data renders in ~500 ms (measured in ADR 002). For PWA-only apps, use `document.addEventListener("visibilitychange", ...)` with the same body.

Optimistic updates patch the client cache synchronously, so UI reflects the change BEFORE the network roundtrip. They persist across disconnects: a tap in airplane mode renders instantly and replays when the WebSocket reopens.

```tsx
import { useMutation } from "convex/react";
import { api } from "../convex/_generated/api";

// Rule: EVERY user-initiated mutation that changes a currently-rendered query
//       should use withOptimisticUpdate. No exceptions.
export function useAddTask() {
  return useMutation(api.tasks.createTask).withOptimisticUpdate(
    (store, { title }) => {
      const list = store.getQuery(api.tasks.listTasks, {});
      if (list === undefined) return;
      store.setQuery(api.tasks.listTasks, {}, [
        {
          _id: crypto.randomUUID() as any,        // temp id replaced on ack
          _creationTime: Date.now(),
          tenantId: "",                           // server fills the real value
          title,
          completed: false,
          createdAt: Date.now(),
        },
        ...list,
      ]);
    },
  );
}
```

NEVER gate optimistic rendering on `navigator.onLine` — the user's intent is the same regardless of network state. The Convex client replaces the temp entry with the server's real row on ack, automatically.

Don't use `navigator.onLine` for sync-status UI — it reports OS network state, not whether the Convex WebSocket is open. `useConvex().connectionState()` knows about both the socket AND in-flight mutations.

```tsx
import { useConvex } from "convex/react";
import { useEffect, useState } from "react";

export function SyncBadge() {
  const convex = useConvex();
  const [state, setState] = useState(convex.connectionState());

  useEffect(() => {
    const id = setInterval(() => setState(convex.connectionState()), 1000);
    return () => clearInterval(id);
  }, [convex]);

  const offline = !state.isWebSocketConnected;
  const pending = state.inflightMutations > 0;

  if (!offline && !pending) return null;

  return (
    <div className="fixed top-14 inset-x-5 z-10 bg-amber-500/90 text-white text-xs py-1.5 px-3 rounded-lg text-center">
      {offline ? "Offline — changes will sync when back online" : `Syncing ${pending} change(s)…`}
    </div>
  );
}
```

`connectionState()` returns `{ isWebSocketConnected, inflightMutations, inflightActions }`. Never disable `useQuery` based on this — it returns cached data during disconnect, giving uninterrupted UI.

Canonical Convex schema for habit / streak / daily-goal apps. Every habit and every check-in row is tenant-scoped; the streak is computed on read, not stored (stale-data-proof).

```ts
// convex/schema.ts
import { defineSchema, defineTable } from "convex/server";
import { v } from "convex/values";

export default defineSchema({
  habits: defineTable({
    tenantId: v.string(),
    name: v.string(),
    color: v.string(),
    createdAt: v.number(),
  }).index("by_tenant", ["tenantId"]),

  completions: defineTable({
    tenantId: v.string(),
    habitId: v.id("habits"),
    dateKey: v.string(),            // "2026-04-21"
    createdAt: v.number(),
  })
    .index("by_tenant", ["tenantId"])
    .index("by_tenant_and_habit", ["tenantId", "habitId"])
    .index("by_tenant_habit_date", ["tenantId", "habitId", "dateKey"]),
});
```

```ts
// convex/habits.ts — toggle today, read the streak
import { v } from "convex/values";
import { tenantQuery, tenantMutation } from "./_helpers";

export const toggleToday = tenantMutation({
  args: { habitId: v.id("habits") },
  handler: async (ctx, { habitId }) => {
    const dateKey = new Date().toISOString().slice(0, 10);
    const existing = await ctx.db
      .query("completions")
      .withIndex("by_tenant_habit_date", (q) =>
        q.eq("tenantId", ctx.tenantId).eq("habitId", habitId).eq("dateKey", dateKey))
      .unique();
    if (existing) {
      await ctx.db.delete(existing._id);
    } else {
      await ctx.db.insert("completions", {
        tenantId: ctx.tenantId, habitId, dateKey, createdAt: Date.now(),
      });
    }
  },
});

export const listHabitsWithStreaks = tenantQuery({
  args: {},
  handler: async (ctx) => {
    const habits = await ctx.db
      .query("habits")
      .withIndex("by_tenant", (q) => q.eq("tenantId", ctx.tenantId))
      .collect();
    return Promise.all(habits.map(async (h) => {
      const done = await ctx.db
        .query("completions")
        .withIndex("by_tenant_and_habit", (q) =>
          q.eq("tenantId", ctx.tenantId).eq("habitId", h._id))
        .collect();
      const keys = new Set(done.map((c) => c.dateKey));
      let streak = 0;
      const d = new Date();
      while (keys.has(d.toISOString().slice(0, 10))) {
        streak++;
        d.setDate(d.getDate() - 1);
      }
      return { ...h, streak, doneToday: keys.has(new Date().toISOString().slice(0, 10)) };
    }));
  },
});
```

Store one completion row per (habit, day) — never boolean flags on the habit row. This way edits are additive, history is queryable, and the streak query is O(completions per habit), not O(days since install).

Canonical Convex schema + query pattern for expense / finance / spending apps with dashboard rollups (e.g., "this month's total spending broken down by category").

```ts
// convex/schema.ts
import { defineSchema, defineTable } from "convex/server";
import { v } from "convex/values";

export default defineSchema({
  transactions: defineTable({
    tenantId: v.string(),
    amount: v.number(),            // cents; positive = income, negative = expense
    category: v.string(),          // "food", "transport", "bills"
    description: v.string(),
    date: v.number(),              // ms since epoch — day-of-transaction
  })
    .index("by_tenant", ["tenantId"])
    .index("by_tenant_and_date", ["tenantId", "date"])
    .index("by_tenant_and_category", ["tenantId", "category"]),
});
```

```ts
// convex/transactions.ts — monthly totals grouped by category for the dashboard
import { v } from "convex/values";
import { tenantQuery, tenantMutation } from "./_helpers";

export const listForMonth = tenantQuery({
  args: { year: v.number(), month: v.number() },    // month is 1..12
  handler: async (ctx, { year, month }) => {
    const start = new Date(Date.UTC(year, month - 1, 1)).getTime();
    const end = new Date(Date.UTC(year, month, 1)).getTime();
    return ctx.db
      .query("transactions")
      .withIndex("by_tenant_and_date", (q) =>
        q.eq("tenantId", ctx.tenantId).gte("date", start).lt("date", end))
      .collect();
  },
});

export const spendingByCategoryThisMonth = tenantQuery({
  args: {},
  handler: async (ctx) => {
    const now = new Date();
    const start = Date.UTC(now.getUTCFullYear(), now.getUTCMonth(), 1);
    const txns = await ctx.db
      .query("transactions")
      .withIndex("by_tenant_and_date", (q) =>
        q.eq("tenantId", ctx.tenantId).gte("date", start))
      .collect();
    const byCat: Record<string, number> = {};
    for (const t of txns) {
      if (t.amount >= 0) continue;                // income excluded
      byCat[t.category] = (byCat[t.category] ?? 0) + Math.abs(t.amount);
    }
    return Object.entries(byCat)
      .map(([category, total]) => ({ category, total }))
      .sort((a, b) => b.total - a.total);
  },
});
```

Aggregation happens in the query handler (one tenant-scoped read, grouped in memory). For month / year boundaries use UTC epoch ms to stay deterministic across timezones. Feed the result directly into a `<Recharts>` pie or bar chart.

Firebase Auth handles OAuth providers (Google / Apple); Convex validates the ID token to authenticate queries. Wire the bridge once at the root, then every `useQuery` / `useMutation` runs as the signed-in user.

```tsx
// src/ConvexClientProvider.tsx
import { ConvexReactClient, ConvexProviderWithAuth } from "convex/react";
import { useAuth } from "@appio/ui/hooks";

const convex = new ConvexReactClient(import.meta.env.VITE_CONVEX_URL);

export function ConvexClientProvider({ children }: { children: React.ReactNode }) {
  return (
    <ConvexProviderWithAuth client={convex} useAuth={useAuth}>
      {children}
    </ConvexProviderWithAuth>
  );
}
```

```tsx
// src/index.tsx
import { AuthProvider } from "@appio/ui/auth";
import { ConvexClientProvider } from "./ConvexClientProvider";

<AuthProvider firebaseConfig={FIREBASE_CONFIG}>
  <ConvexClientProvider>
    <App />
  </ConvexClientProvider>
</AuthProvider>
```

Inside Convex handlers, `identity.subject` IS the Firebase uid. The `tenantQuery` / `tenantMutation` helpers resolve it once and expose `ctx.tenantId` (see the tenant isolation snippet). Convex's `auth.config.ts` validates the Firebase issuer URL — no deploy key is ever exposed to the browser.

