Dialog-based command palette with grouped results, keyboard navigation (↑↓ Enter Esc), and keyword matching. Controlled open state.

```tsx
import { CommandPalette } from "@appio/layout-blocks";

const [open, setOpen] = useState(false);

// Global ⌘K / Ctrl+K shortcut
useEffect(() => {
  const handler = (e: KeyboardEvent) => {
    if ((e.metaKey || e.ctrlKey) && e.key === "k") { e.preventDefault(); setOpen(o => !o); }
  };
  window.addEventListener("keydown", handler);
  return () => window.removeEventListener("keydown", handler);
}, []);

<CommandPalette
  open={open}
  onOpenChange={setOpen}
  groups={[
    {
      id: "nav", heading: "Navigation",
      items: [
        { id: "home", label: "Go Home", shortcut: "⌘H", onSelect: () => router.push("/") },
        { id: "apps", label: "My Apps", keywords: ["apps", "projects"], onSelect: () => router.push("/apps") },
      ],
    },
  ]}
/>
```

Items match against `label` + `description` + `keywords`. Closes on select by default — set `closeOnSelect={false}` for multi-action flows.
